#!/usr/bin/env node
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
import axios, { AxiosInstance } from "axios";

// ─── Configuration ────────────────────────────────────────────────────────────
const COGNOS_URL = process.env.COGNOS_URL || "http://ibmdemos:9300/bi/";
const COGNOS_USERNAME = process.env.COGNOS_USERNAME || "pm";
const COGNOS_PASSWORD = process.env.COGNOS_PASSWORD || "IBMDem0s";
const COGNOS_NAMESPACE = process.env.COGNOS_NAMESPACE || "CognosEx";

// Strip trailing slash and build the v1 API base
const baseUrl = COGNOS_URL.replace(/\/$/, "");
const apiBase = `${baseUrl}/v1`;

// ─── HTTP Client ──────────────────────────────────────────────────────────────
const client: AxiosInstance = axios.create({
  baseURL: apiBase,
  timeout: 30000,
  // Self-signed / internal certs — allow in lab environments
  httpsAgent: process.env.COGNOS_REJECT_TLS === "true"
    ? undefined
    : new (require("https").Agent)({ rejectUnauthorized: false }),
  headers: { "Content-Type": "application/json" },
});

// ─── Session Management ───────────────────────────────────────────────────────
let sessionCookie: string | null = null;
let csrfToken: string | null = null;

async function login(): Promise<void> {
  try {
    const payload = {
      parameters: [
        { name: "CAMNamespace", value: COGNOS_NAMESPACE },
        { name: "CAMUsername", value: COGNOS_USERNAME },
        { name: "CAMPassword", value: COGNOS_PASSWORD },
      ],
    };
    const response = await client.put("/session", payload);
    const setCookie = response.headers["set-cookie"];
    if (setCookie) {
      sessionCookie = setCookie
        .map((c: string) => c.split(";")[0])
        .join("; ");
    }
    csrfToken = response.headers["x-csrf-token"] ||
                response.data?.session?.csrfToken ||
                null;
    if (!sessionCookie) {
      throw new Error("No session cookie received from Cognos");
    }
    console.error(`[cognos-mcp] Logged in as ${COGNOS_USERNAME} on namespace ${COGNOS_NAMESPACE}`);
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    throw new Error(`Cognos login failed: ${msg}`);
  }
}

function sessionHeaders(): Record<string, string> {
  const headers: Record<string, string> = {};
  if (sessionCookie) headers["Cookie"] = sessionCookie;
  if (csrfToken) headers["X-XSRF-TOKEN"] = csrfToken;
  return headers;
}

async function apiGet<T>(path: string, params?: Record<string, string>): Promise<T> {
  if (!sessionCookie) await login();
  try {
    const response = await client.get<T>(path, {
      headers: sessionHeaders(),
      params,
    });
    return response.data;
  } catch (err: unknown) {
    const axErr = err as { response?: { status?: number } };
    if (axErr?.response?.status === 401) {
      sessionCookie = null;
      csrfToken = null;
      await login();
      const retry = await client.get<T>(path, {
        headers: sessionHeaders(),
        params,
      });
      return retry.data;
    }
    throw err;
  }
}

async function apiPost<T>(path: string, body: unknown): Promise<T> {
  if (!sessionCookie) await login();
  const response = await client.post<T>(path, body, {
    headers: sessionHeaders(),
  });
  return response.data;
}

// ─── MCP Server ───────────────────────────────────────────────────────────────
const server = new McpServer({
  name: "cognos-analytics",
  version: "1.0.0",
});

// ── Tool: list-reports ────────────────────────────────────────────────────────
server.registerTool(
  "list-reports",
  {
    description:
      "List reports available in IBM Cognos Analytics. Optionally filter by a parent folder ID.",
    inputSchema: z.object({
      folderId: z
        .string()
        .optional()
        .describe("ID of the folder to list. Omit to list the root content."),
      searchTerm: z
        .string()
        .optional()
        .describe("Optional keyword to filter results by name."),
    }),
  },
  async ({ folderId, searchTerm }) => {
    try {
      let data: unknown;
      if (folderId) {
        data = await apiGet(`/content/${folderId}/items`);
      } else {
        data = await apiGet("/content");
      }
      // Filter by search term if provided
      const items: unknown[] = Array.isArray((data as { resources?: unknown[] })?.resources)
        ? ((data as { resources: unknown[] }).resources)
        : Array.isArray(data)
        ? (data as unknown[])
        : [];
      const filtered = searchTerm
        ? items.filter((item) =>
            typeof (item as { defaultName?: string }).defaultName === "string" &&
            (item as { defaultName: string }).defaultName
              .toLowerCase()
              .includes(searchTerm.toLowerCase())
          )
        : items;
      return {
        content: [
          {
            type: "text" as const,
            text: JSON.stringify({ total: filtered.length, items: filtered }, null, 2),
          },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error listing reports: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: get-report-info ─────────────────────────────────────────────────────
server.registerTool(
  "get-report-info",
  {
    description: "Get metadata and details about a specific Cognos report by its ID.",
    inputSchema: z.object({
      reportId: z.string().describe("The Cognos content store ID of the report."),
    }),
  },
  async ({ reportId }) => {
    try {
      const data = await apiGet(`/content/${reportId}`);
      return {
        content: [
          { type: "text" as const, text: JSON.stringify(data, null, 2) },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error fetching report info: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: run-report ──────────────────────────────────────────────────────────
server.registerTool(
  "run-report",
  {
    description:
      "Run a Cognos Analytics report and return its output. Supports HTML, PDF, CSV, and Excel output formats.",
    inputSchema: z.object({
      reportId: z.string().describe("The Cognos content store ID of the report to run."),
      format: z
        .enum(["HTML", "PDF", "CSV", "spreadsheetML"])
        .optional()
        .describe("Output format. Defaults to HTML."),
      parameters: z
        .record(z.string())
        .optional()
        .describe("Optional key-value map of report parameters."),
    }),
  },
  async ({ reportId, format = "HTML", parameters }) => {
    try {
      const reportParams: Array<{ name: string; value: string }> = parameters
        ? Object.entries(parameters).map(([name, value]) => ({ name, value }))
        : [];

      const body = {
        reportId,
        format,
        ...(reportParams.length > 0 ? { parameters: reportParams } : {}),
      };

      const data = await apiPost("/reports/run", body);
      return {
        content: [
          { type: "text" as const, text: JSON.stringify(data, null, 2) },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error running report: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: search-content ──────────────────────────────────────────────────────
server.registerTool(
  "search-content",
  {
    description: "Search the Cognos Analytics content store for reports, dashboards, and data modules by keyword.",
    inputSchema: z.object({
      query: z.string().describe("Search keyword or phrase."),
      type: z
        .enum(["report", "dashboard", "dataSet2", "module", "folder"])
        .optional()
        .describe("Restrict results to a specific content type."),
      limit: z
        .number()
        .int()
        .min(1)
        .max(200)
        .optional()
        .describe("Maximum number of results to return (1–200). Default 25."),
    }),
  },
  async ({ query, type, limit = 25 }) => {
    try {
      const params: Record<string, string> = {
        q: query,
        limit: String(limit),
      };
      if (type) params["types"] = type;

      const data = await apiGet("/search", params);
      return {
        content: [
          { type: "text" as const, text: JSON.stringify(data, null, 2) },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error searching content: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: list-datasources ────────────────────────────────────────────────────
server.registerTool(
  "list-datasources",
  {
    description: "List all data sources configured in Cognos Analytics.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const data = await apiGet("/datasources");
      return {
        content: [
          { type: "text" as const, text: JSON.stringify(data, null, 2) },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error listing datasources: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: get-schedules ───────────────────────────────────────────────────────
server.registerTool(
  "get-schedules",
  {
    description: "List scheduled activities for a specific report or for all reports.",
    inputSchema: z.object({
      reportId: z
        .string()
        .optional()
        .describe("Cognos report ID. If omitted, all schedules are returned."),
    }),
  },
  async ({ reportId }) => {
    try {
      const path = reportId
        ? `/content/${reportId}/schedules`
        : "/schedules";
      const data = await apiGet(path);
      return {
        content: [
          { type: "text" as const, text: JSON.stringify(data, null, 2) },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error fetching schedules: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: list-folders ────────────────────────────────────────────────────────
server.registerTool(
  "list-folders",
  {
    description: "List top-level folders and namespaces in the Cognos content store.",
