  async ({ folderId, searchTerm }) => {
    try {
      let data: unknown;
      if (folderId) {
        data = await apiGet(`/content/${folderId}/items`);
      } else {
        data = await apiGet("/content");
      }
      // Filter by search term if provided
      const items: unknown[] = Array.isArray((data as { resources?: unknown[] })?.resources)
        ? ((data as { resources: unknown[] }).resources)
        : Array.isArray(data)
        ? (data as unknown[])
        : [];
      const filtered = searchTerm
        ? items.filter((item) =>
            typeof (item as { defaultName?: string }).defaultName === "string" &&
            (item as { defaultName: string }).defaultName
              .toLowerCase()
              .includes(searchTerm.toLowerCase())
          )
        : items;
