  async ({ reportId, format = "HTML", parameters }) => {
    try {
      const reportParams: Array<{ name: string; value: string }> = parameters
        ? Object.entries(parameters).map(([name, value]) => ({ name, value }))
        : [];

      const body = {
        reportId,
        format,
        ...(reportParams.length > 0 ? { parameters: reportParams } : {}),
      };

      const data = await apiPost("/reports/run", body);
      return {
        content: [
          { type: "text" as const, text: JSON.stringify(data, null, 2) },
        ],
      };
    } catch (err: unknown) {
      return {
        content: [{ type: "text" as const, text: `Error running report: ${err instanceof Error ? err.message : String(err)}` }],
        isError: true,
      };
    }
  }
);

// ── Tool: search-content ──────────────────────────────────────────────────────
