#!/usr/bin/env node
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
import axios, { AxiosInstance } from "axios";
import * as https from "https";

// ─── Configuration ────────────────────────────────────────────────────────────
const COGNOS_URL       = (process.env.COGNOS_URL       || "http://ibmdemos:9300/bi/").replace(/\/$/, "");
const COGNOS_USERNAME  = process.env.COGNOS_USERNAME  || "pm";
const COGNOS_PASSWORD  = process.env.COGNOS_PASSWORD  || "IBMDem0s";
const COGNOS_NAMESPACE = process.env.COGNOS_NAMESPACE || "Harmony LDAP";

const apiBase = `${COGNOS_URL}/v1`;

// ─── HTTP Client ──────────────────────────────────────────────────────────────
const httpsAgent = new https.Agent({ rejectUnauthorized: false });

const client: AxiosInstance = axios.create({
  baseURL: apiBase,
  timeout: 30_000,
  httpsAgent,
  headers: { "Content-Type": "application/json", Accept: "application/json" },
  // Keep axios from throwing on 4xx so we can read bodies ourselves
  validateStatus: () => true,
  withCredentials: false,
});

// ─── Session State ────────────────────────────────────────────────────────────
let cookieHeader: string = "";   // full "name=value; name=value" string to send
let xsrfToken:    string = "";   // value of XSRF-TOKEN cookie
let sessionValid  = false;

/**
 * Parse Set-Cookie headers into a flat "name=value" cookie string and extract
 * the XSRF-TOKEN value for the X-XSRF-TOKEN request header.
 */
function updateCookies(setCookieHeaders: string | string[] | undefined): void {
  if (!setCookieHeaders) return;
  const headers = Array.isArray(setCookieHeaders) ? setCookieHeaders : [setCookieHeaders];
  const map = new Map<string, string>();
  // Preserve existing cookies first
  if (cookieHeader) {
    cookieHeader.split(";").forEach((part) => {
      const [k, v] = part.trim().split("=");
      if (k) map.set(k.trim(), v?.trim() ?? "");
    });
  }
  // Merge new cookies (first segment of each Set-Cookie)
  for (const header of headers) {
    const segment = header.split(";")[0].trim();
    const eqIdx   = segment.indexOf("=");
    if (eqIdx < 0) continue;
    const name  = segment.substring(0, eqIdx).trim();
    const value = segment.substring(eqIdx + 1).trim();
    map.set(name, value);
    if (name === "XSRF-TOKEN") xsrfToken = value;
  }
  cookieHeader = [...map.entries()].map(([k, v]) => `${k}=${v}`).join("; ");
}

function authHeaders(): Record<string, string> {
  const h: Record<string, string> = {};
  if (cookieHeader) h["Cookie"]      = cookieHeader;
  if (xsrfToken)    h["X-XSRF-TOKEN"] = xsrfToken;
  return h;
}

/** Full Cognos login sequence:
 *  1. GET /ping  — seeds XSRF-TOKEN cookie
 *  2. GET /login — seeds session cookie, returns 441 challenge (expected)
 *  3. POST /login with namespace + credentials — returns 200 with session
 */
async function login(): Promise<void> {
  // Step 1 — seed XSRF-TOKEN
  const ping = await client.get("/ping");
  updateCookies(ping.headers["set-cookie"]);
  console.error(`[cognos-mcp] XSRF seeded: ${xsrfToken.substring(0, 10)}...`);

  // Step 2 — get login challenge (441 is expected here)
  const challenge = await client.get("/login", { headers: authHeaders() });
  updateCookies(challenge.headers["set-cookie"]);

  // Step 3 — authenticate
  const body = {
    parameters: [
      { name: "CAMNamespace", value: COGNOS_NAMESPACE },
      { name: "CAMUsername",  value: COGNOS_USERNAME  },
      { name: "CAMPassword",  value: COGNOS_PASSWORD  },
    ],
  };
  const resp = await client.post("/login", body, { headers: authHeaders() });
  updateCookies(resp.headers["set-cookie"]);

  if (resp.status !== 200) {
    throw new Error(
      `Cognos login failed (HTTP ${resp.status}): ${JSON.stringify(resp.data)}`
    );
  }
  sessionValid = true;
  console.error(`[cognos-mcp] Logged in as "${COGNOS_USERNAME}" (namespace: ${COGNOS_NAMESPACE})`);
}

/** Ensure we have a valid session, re-logging in if expired. */
async function ensureSession(): Promise<void> {
  if (!sessionValid) await login();
}

/** GET wrapper with auto-reauth on 441. */
async function apiGet<T>(path: string, params?: Record<string, string>): Promise<T> {
  await ensureSession();
  let resp = await client.get<T>(path, { headers: authHeaders(), params });
  if (resp.status === 441) {
    console.error("[cognos-mcp] Session expired, re-authenticating...");
    sessionValid = false;
    await login();
    resp = await client.get<T>(path, { headers: authHeaders(), params });
  }
  if (resp.status >= 400) {
    throw new Error(`GET ${path} failed (HTTP ${resp.status}): ${JSON.stringify(resp.data)}`);
  }
  return resp.data;
}

/** POST wrapper with auto-reauth on 441. */
async function apiPost<T>(path: string, body: unknown): Promise<T> {
  await ensureSession();
  let resp = await client.post<T>(path, body, { headers: authHeaders() });
  if (resp.status === 441) {
    console.error("[cognos-mcp] Session expired, re-authenticating...");
    sessionValid = false;
    await login();
    resp = await client.post<T>(path, body, { headers: authHeaders() });
  }
  if (resp.status >= 400) {
    throw new Error(`POST ${path} failed (HTTP ${resp.status}): ${JSON.stringify(resp.data)}`);
  }
  return resp.data;
}

// ─── MCP Server ───────────────────────────────────────────────────────────────
const server = new McpServer({ name: "cognos-analytics", version: "1.0.0" });

// ── Tool: list-folders ────────────────────────────────────────────────────────
server.registerTool(
  "list-folders",
  {
    description:
      "List folders and top-level items in the Cognos Analytics content store. " +
      "Leave parentId empty to see the root. Pass a parentId to drill into a folder.",
    inputSchema: z.object({
      parentId: z
        .string()
        .optional()
        .describe("Cognos object ID of the parent folder. Omit for root."),
    }),
  },
  async ({ parentId }) => {
    try {
      type ContentResp = { resources?: unknown[] };
      const path = parentId ? `/content/${parentId}/items` : "/content";
      const data = await apiGet<ContentResp>(path);
      const items: unknown[] = Array.isArray(data?.resources) ? data.resources : [];
      return {
        content: [
          {
            type: "text" as const,
            text: JSON.stringify({ total: items.length, items }, null, 2),
          },
        ],
      };
    } catch (err) {
      return errResult("list-folders", err);
    }
  }
);

// ── Tool: list-reports ────────────────────────────────────────────────────────
server.registerTool(
  "list-reports",
  {
    description:
      "List reports (and optionally other content types) inside a Cognos folder. " +
      "Uses the root content store when no folderId is supplied.",
    inputSchema: z.object({
      folderId: z
        .string()
        .optional()
        .describe("ID of the folder to list. Omit for root."),
      searchTerm: z
        .string()
        .optional()
        .describe("Filter results by name (case-insensitive substring)."),
    }),
  },
  async ({ folderId, searchTerm }) => {
    try {
      type ContentResp = { resources?: unknown[] };
      const path = folderId ? `/content/${folderId}/items` : "/content";
      const data = await apiGet<ContentResp>(path);
      let items: unknown[] = Array.isArray(data?.resources) ? data.resources : [];
      if (searchTerm) {
        items = items.filter(
          (item) =>
            typeof (item as { defaultName?: string }).defaultName === "string" &&
            (item as { defaultName: string }).defaultName
              .toLowerCase()
              .includes(searchTerm.toLowerCase())
        );
      }
      return {
        content: [
