#!/usr/bin/env node
/**
 * IBM Cognos Analytics MCP Server
 *
 * Auth flow (verified against ibmdemos:9300):
 *   1. GET  /v1/ping              — seeds XSRF-TOKEN cookie
 *   2. GET  /v1/login             — seeds session cookie (441 is expected/normal)
 *   3. POST /v1/login  {parameters:[CAMNamespace, CAMUsername, CAMPassword]}
 *                                 — returns 200 with full session cookies
 *
 * Key endpoints (verified):
 *   /v1/namespaces                — list namespaces (root "Cognos" id = "xOg__")
 *   /v1/objects/{id}              — get a single object
 *   /v1/objects/{id}/items        — list children of an object/folder
 *   /v1/folders                   — data-source focused folder list
 *   /v1/users/~/favorites         — current user's favorites
 *   /v1/users/~/recents           — current user's recents
 *   /v1/datasources               — all configured data sources
 *   /v1/search?q=...              — full-text search
 */
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
import axios, { AxiosInstance } from "axios";
import * as https from "https";

// ─── Configuration ────────────────────────────────────────────────────────────
const COGNOS_URL       = (process.env.COGNOS_URL       || "http://ibmdemos:9300/bi/").replace(/\/$/, "");
const COGNOS_USERNAME  = process.env.COGNOS_USERNAME  || "pm";
const COGNOS_PASSWORD  = process.env.COGNOS_PASSWORD  || "IBMDem0s";
const COGNOS_NAMESPACE = process.env.COGNOS_NAMESPACE || "Harmony LDAP";

// Root namespace object ID (the built-in "Cognos" namespace — constant across installations)
const COGNOS_NS_ROOT   = process.env.COGNOS_NS_ROOT   || "xOg__";

const apiBase = `${COGNOS_URL}/v1`;

// ─── HTTP Client ──────────────────────────────────────────────────────────────
const client: AxiosInstance = axios.create({
  baseURL: apiBase,
  timeout: 30_000,
  httpsAgent: new https.Agent({ rejectUnauthorized: false }),
  headers: { "Content-Type": "application/json", Accept: "application/json" },
  validateStatus: () => true,   // never throw on HTTP error codes
});

// ─── Session State ────────────────────────────────────────────────────────────
let cookieJar: Map<string, string> = new Map();
let xsrfToken  = "";
let sessionValid = false;

function updateCookies(raw: string | string[] | undefined): void {
  if (!raw) return;
  const headers = Array.isArray(raw) ? raw : [raw];
  for (const h of headers) {
    const seg   = h.split(";")[0].trim();
    const eq    = seg.indexOf("=");
    if (eq < 0) continue;
    const name  = seg.substring(0, eq).trim();
    const value = seg.substring(eq + 1).trim();
    cookieJar.set(name, value);
    if (name === "XSRF-TOKEN") xsrfToken = value;
  }
}

function cookieString(): string {
  return [...cookieJar.entries()].map(([k, v]) => `${k}=${v}`).join("; ");
}

function authHeaders(): Record<string, string> {
  const h: Record<string, string> = {};
  const c = cookieString();
  if (c)         h["Cookie"]       = c;
  if (xsrfToken) h["X-XSRF-TOKEN"] = xsrfToken;
  return h;
}

/** Three-step Cognos login sequence. */
async function login(): Promise<void> {
  // Reset state
  cookieJar   = new Map();
  xsrfToken   = "";
  sessionValid = false;

  // Step 1 — seed XSRF-TOKEN
  const ping = await client.get("/ping");
  updateCookies(ping.headers["set-cookie"]);

  // Step 2 — challenge (441 is expected)
  const chal = await client.get("/login", { headers: authHeaders() });
  updateCookies(chal.headers["set-cookie"]);

  // Step 3 — authenticate
  const resp = await client.post("/login", {
    parameters: [
      { name: "CAMNamespace", value: COGNOS_NAMESPACE },
      { name: "CAMUsername",  value: COGNOS_USERNAME  },
      { name: "CAMPassword",  value: COGNOS_PASSWORD  },
    ],
  }, { headers: authHeaders() });

  updateCookies(resp.headers["set-cookie"]);

  if (resp.status !== 200) {
    throw new Error(`Cognos login failed (HTTP ${resp.status}): ${JSON.stringify(resp.data)}`);
  }
  sessionValid = true;
  console.error(`[cognos-mcp] Logged in as "${COGNOS_USERNAME}" on "${COGNOS_NAMESPACE}"`);
}

async function ensureSession(): Promise<void> {
  if (!sessionValid) await login();
}

/** GET with auto-reauth on 441. */
async function apiGet<T = unknown>(path: string, params?: Record<string, string>): Promise<T> {
  await ensureSession();
  let r = await client.get<T>(path, { headers: authHeaders(), params });
  if (r.status === 441) {
    console.error("[cognos-mcp] Session expired — re-logging in...");
    await login();
    r = await client.get<T>(path, { headers: authHeaders(), params });
  }
  if (r.status >= 400) throw new Error(`GET ${path} → HTTP ${r.status}: ${JSON.stringify(r.data)}`);
  return r.data;
}

// ─── Shared types ─────────────────────────────────────────────────────────────
interface CognosItem {
  id:           string;
  type:         string;
  defaultName?: string;
  objectClass?: string;
  hasChildren?: boolean;
  modificationTime?: string;
  _meta?:       { links?: { self?: { url?: string }; items?: { url?: string } } };
}

interface ListResp { data?: CognosItem[] }

// ─── MCP Server ───────────────────────────────────────────────────────────────
const server = new McpServer({ name: "cognos-analytics", version: "1.0.0" });

// ── Tool: list-namespaces ─────────────────────────────────────────────────────
server.registerTool(
  "list-namespaces",
  {
    description: "List all top-level namespaces in the Cognos Analytics content store. Start here to discover root folder IDs.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const data = await apiGet<ListResp>("/namespaces");
      const items = data?.data ?? [];
      return ok(JSON.stringify({ total: items.length, namespaces: items }, null, 2));
    } catch (err) { return fail("list-namespaces", err); }
  }
);

// ── Tool: list-items ──────────────────────────────────────────────────────────
server.registerTool(
  "list-items",
  {
    description:
      "List the children (folders, reports, dashboards, etc.) of any Cognos object by its ID. " +
      "Use list-namespaces first to get the root namespace ID (e.g. xOg__), then drill in with this tool. " +
      "Leave objectId blank to list the built-in Cognos namespace root.",
    inputSchema: z.object({
      objectId: z
        .string()
        .optional()
        .describe("Cognos object ID whose children to list. Omit for namespace root."),
