  const resp = await client.post("/login", {
    parameters: [
      { name: "CAMNamespace", value: COGNOS_NAMESPACE },
      { name: "CAMUsername",  value: COGNOS_USERNAME  },
      { name: "CAMPassword",  value: COGNOS_PASSWORD  },
    ],
  }, { headers: authHeaders() });

  updateCookies(resp.headers["set-cookie"]);

  if (resp.status !== 200) {
    throw new Error(`Cognos login failed (HTTP ${resp.status}): ${JSON.stringify(resp.data)}`);
  }
  sessionValid = true;
  console.error(`[cognos-mcp] Logged in as "${COGNOS_USERNAME}" on "${COGNOS_NAMESPACE}"`);
}

async function ensureSession(): Promise<void> {
  if (!sessionValid) await login();
}

/** GET with auto-reauth on 441. */
async function apiGet<T = unknown>(path: string, params?: Record<string, string>): Promise<T> {
  await ensureSession();
  let r = await client.get<T>(path, { headers: authHeaders(), params });
  if (r.status === 441) {
    console.error("[cognos-mcp] Session expired — re-logging in...");
    await login();
    r = await client.get<T>(path, { headers: authHeaders(), params });
  }
  if (r.status >= 400) throw new Error(`GET ${path} → HTTP ${r.status}: ${JSON.stringify(r.data)}`);
  return r.data;
}

/** POST with auto-reauth on 441. */
async function apiPost<T = unknown>(path: string, body: unknown): Promise<{ status: number; data: T }> {
  await ensureSession();
  let r = await client.post<T>(path, body, { headers: authHeaders() });
  if (r.status === 441) {
    await login();
    r = await client.post<T>(path, body, { headers: authHeaders() });
  }
  return { status: r.status, data: r.data };
}

/** PUT with auto-reauth on 441. */
async function apiPut<T = unknown>(path: string, body: unknown): Promise<{ status: number; data: T }> {
  await ensureSession();
  let r = await client.put<T>(path, body, { headers: authHeaders() });
  if (r.status === 441) {
    await login();
    r = await client.put<T>(path, body, { headers: authHeaders() });
  }
  return { status: r.status, data: r.data };
}

/** DELETE with auto-reauth on 441. */
async function apiDelete<T = unknown>(path: string): Promise<{ status: number; data: T }> {
  await ensureSession();
  let r = await client.delete<T>(path, { headers: authHeaders() });
  if (r.status === 441) {
    await login();
    r = await client.delete<T>(path, { headers: authHeaders() });
  }
  return { status: r.status, data: r.data };
}

// ─── Shared types ─────────────────────────────────────────────────────────────
interface CognosItem {
  id:           string;
  type:         string;
  defaultName?: string;
  objectClass?: string;
  hasChildren?: boolean;
  modificationTime?: string;
  _meta?:       { links?: { self?: { url?: string }; items?: { url?: string } } };
}

interface ListResp { data?: CognosItem[] }

// ─── MCP Server ───────────────────────────────────────────────────────────────
const server = new McpServer({ name: "cognos-analytics", version: "1.0.0" });

// ── Tool: list-namespaces ─────────────────────────────────────────────────────
server.registerTool(
  "list-namespaces",
  {
    description: "List all top-level namespaces in the Cognos Analytics content store. Start here to discover root folder IDs.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const data = await apiGet<ListResp>("/namespaces");
      const items = data?.data ?? [];
      return ok(JSON.stringify({ total: items.length, namespaces: items }, null, 2));
    } catch (err) { return fail("list-namespaces", err); }
  }
);

// ── Tool: list-items ──────────────────────────────────────────────────────────
server.registerTool(
  "list-items",
  {
    description:
      "List the children (folders, reports, dashboards, etc.) of any Cognos object by its ID. " +
      "Use list-namespaces first to get the root namespace ID (e.g. xOg__), then drill in with this tool. " +
      "Leave objectId blank to list the built-in Cognos namespace root.",
    inputSchema: z.object({
      objectId: z
        .string()
        .optional()
        .describe("Cognos object ID whose children to list. Omit for namespace root."),
      filterType: z
        .string()
        .optional()
        .describe("Filter by type, e.g. 'report', 'folder', 'dashboard', 'dataSource'."),
    }),
  },
  async ({ objectId, filterType }) => {
    try {
      const id   = objectId || COGNOS_NS_ROOT;
      const data = await apiGet<ListResp>(`/objects/${id}/items`);
      let items: CognosItem[] = data?.data ?? [];
      if (filterType) {
        items = items.filter((i) => i.type?.toLowerCase() === filterType.toLowerCase()
          || i.objectClass?.toLowerCase() === filterType.toLowerCase());
      }
      const summary = items.map((i) => ({
        id: i.id,
        type: i.type,
        defaultName: i.defaultName,
        hasChildren: i.hasChildren,
        modificationTime: i.modificationTime,
      }));
      return ok(JSON.stringify({ total: summary.length, items: summary }, null, 2));
    } catch (err) { return fail("list-items", err); }
  }
);

// ── Tool: get-object ──────────────────────────────────────────────────────────
server.registerTool(
  "get-object",
  {
    description: "Get full metadata for any Cognos object (report, folder, dashboard, datasource, etc.) by its ID.",
    inputSchema: z.object({
      objectId: z.string().describe("Cognos content store ID of the object."),
    }),
  },
  async ({ objectId }) => {
    try {
      const data = await apiGet(`/objects/${objectId}`);
      return ok(JSON.stringify(data, null, 2));
    } catch (err) { return fail("get-object", err); }
  }
);

// ── Tool: search-content ──────────────────────────────────────────────────────
server.registerTool(
  "search-content",
  {
    description: "Full-text search across all Cognos Analytics content: reports, dashboards, data modules, folders.",
    inputSchema: z.object({
      query: z.string().describe("Keyword or phrase to search for."),
      type: z
        .string()
        .optional()
        .describe("Restrict to a content type, e.g. 'report', 'dashboard', 'folder'."),
      limit: z
        .number().int().min(1).max(200).optional()
        .describe("Maximum results (1–200). Default 25."),
    }),
  },
  async ({ query, type, limit = 25 }) => {
    try {
      const params: Record<string, string> = { q: query, limit: String(limit) };
      if (type) params["types"] = type;
      const data = await apiGet("/search", params);
      return ok(JSON.stringify(data, null, 2));
    } catch (err) { return fail("search-content", err); }
  }
);

// ── Tool: list-favorites ──────────────────────────────────────────────────────
server.registerTool(
  "list-favorites",
  {
    description: "List the current user's favorite reports and dashboards in Cognos Analytics.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const data = await apiGet<unknown[]>("/users/~/favorites");
      const list = Array.isArray(data) ? data : [];
      const items = list.flatMap((entry: unknown) => {
        const e = entry as { list?: CognosItem[] };
        return e?.list ?? [];
      });
      const summary = items.map((i) => ({
        id: i.id,
        type: i.type,
        defaultName: i.defaultName,
        modificationTime: i.modificationTime,
      }));
      return ok(JSON.stringify({ total: summary.length, favorites: summary }, null, 2));
    } catch (err) { return fail("list-favorites", err); }
  }
);

// ── Tool: list-recents ────────────────────────────────────────────────────────
server.registerTool(
  "list-recents",
  {
    description: "List the current user's recently viewed reports and content in Cognos Analytics.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const data = await apiGet("/users/~/recents");
      return ok(JSON.stringify(data, null, 2));
    } catch (err) { return fail("list-recents", err); }
  }
);

// ── Tool: list-datasources ────────────────────────────────────────────────────
server.registerTool(
  "list-datasources",
  {
    description: "List all data sources configured in IBM Cognos Analytics.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      const data = await apiGet<ListResp>("/datasources");
      const items = data?.data ?? [];
      const summary = items.map((i) => ({
        id: i.id,
        defaultName: i.defaultName,
        type: i.type,
      }));
      return ok(JSON.stringify({ total: summary.length, datasources: summary }, null, 2));
    } catch (err) { return fail("list-datasources", err); }
  }
);

// ── Tool: get-session-info ────────────────────────────────────────────────────
server.registerTool(
  "get-session-info",
  {
    description: "Return information about the current Cognos Analytics session: logged-in user, namespace, capabilities.",
    inputSchema: z.object({}),
  },
  async () => {
    try {
      // /v1/session returns 404 on this build; use the login response data cached at startup
      // Instead report what we know from the session state
      await ensureSession();
      return ok(JSON.stringify({
        connected: sessionValid,
        url:       COGNOS_URL,
        namespace: COGNOS_NAMESPACE,
        username:  COGNOS_USERNAME,
      }, null, 2));
    } catch (err) { return fail("get-session-info", err); }
  }
);

// ── Tool: create-folder ───────────────────────────────────────────────────────
server.registerTool(
  "create-folder",
  {
    description:
      "Create a new folder inside a Cognos Analytics content store location. " +
      "Use list-items to find a parent folder ID first. " +
      "To create in your personal space, use parentId 'i11D7FDC059B747CBB416A0E7FA8424F7' (My Folders).",
    inputSchema: z.object({
      parentId: z
        .string()
        .describe("ID of the parent folder to create the new folder inside."),
      name: z
        .string()
        .describe("Display name for the new folder."),
    }),
  },
  async ({ parentId, name }) => {
    try {
      const { status, data } = await apiPost(`/objects/${parentId}/items`, {
        type: "folder",
        defaultName: name,
      });
      if (status === 201 || status === 200) {
        const obj = data as { id?: string; defaultName?: string; searchPath?: string };
        return ok(JSON.stringify({
          success: true,
          id:          obj.id,
          defaultName: obj.defaultName ?? name,
          searchPath:  obj.searchPath,
        }, null, 2));
      }
      throw new Error(`HTTP ${status}: ${JSON.stringify(data)}`);
    } catch (err) { return fail("create-folder", err); }
  }
);

// ── Tool: update-object ───────────────────────────────────────────────────────
server.registerTool(
  "update-object",
  {
    description:
      "Rename or update the display name of a Cognos Analytics object (folder, report, dashboard, etc.). " +
      "You must supply the object's current type (e.g. 'folder', 'report', 'exploration').",
    inputSchema: z.object({
      objectId: z
        .string()
        .describe("Cognos ID of the object to update."),
      newName: z
        .string()
        .describe("New display name for the object."),
      type: z
        .string()
        .describe("Type of the object, e.g. 'folder', 'report', 'exploration'. Required by the API."),
    }),
  },
  async ({ objectId, newName, type }) => {
    try {
      const { status, data } = await apiPut(`/objects/${objectId}`, {
        type,
        defaultName: newName,
      });
      if (status === 200 || status === 204) {
        return ok(JSON.stringify({
          success: true,
          objectId,
          newName,
          httpStatus: status,
        }, null, 2));
      }
      throw new Error(`HTTP ${status}: ${JSON.stringify(data)}`);
    } catch (err) { return fail("update-object", err); }
  }
);

// ── Tool: delete-object ───────────────────────────────────────────────────────
server.registerTool(
  "delete-object",
  {
    description:
      "Permanently delete a Cognos Analytics object by its ID. " +
      "This is irreversible — use with caution. Works on folders, reports, dashboards, and other content items.",
    inputSchema: z.object({
      objectId: z
        .string()
        .describe("Cognos ID of the object to delete."),
    }),
  },
  async ({ objectId }) => {
    try {
      const { status, data } = await apiDelete(`/objects/${objectId}`);
      if (status === 200 || status === 204) {
        return ok(JSON.stringify({ success: true, deleted: objectId, httpStatus: status }, null, 2));
      }
      throw new Error(`HTTP ${status}: ${JSON.stringify(data)}`);
    } catch (err) { return fail("delete-object", err); }
  }
);

// ── Tool: run-report ──────────────────────────────────────────────────────────
server.registerTool(
  "run-report",
  {
    description:
      "Execute a Cognos Analytics report by its content store ID using the Report Data Service (RDS). " +
      "Returns the report output. Use get-object or list-items to find a report ID first. " +
      "Supported output formats: HTML, PDF, CSV, spreadsheetML (Excel), XML.",
    inputSchema: z.object({
      reportId: z
        .string()
        .describe("Cognos content store ID of the report to run."),
      outputFormat: z
        .enum(["HTML", "PDF", "CSV", "spreadsheetML", "XML"])
        .optional()
        .describe("Output format. Defaults to HTML."),
      parameters: z
        .record(z.string(), z.string())
        .optional()
        .describe("Optional report prompt parameters as key-value pairs."),
    }),
  },
  async ({ reportId, outputFormat = "HTML", parameters }) => {
    try {
      const params: Record<string, string> = {
        id:  reportId,
        fmt: outputFormat,
      };
      const { status, data } = await apiPost<string>("/disp/rds/reportData/report", {
        id:           reportId,
        outputFormat,
        ...(parameters ? { parameters: Object.entries(parameters).map(([name, value]) => ({ name, value })) } : {}),
      });
      if (status === 200) {
        const text = typeof data === "string" ? data : JSON.stringify(data, null, 2);
        // Truncate very large outputs to avoid overwhelming the context
        const truncated = text.length > 20000;
        return ok(
          truncated
            ? text.substring(0, 20000) + `\n\n... [truncated — ${text.length} total chars]`
            : text
        );
      }
      throw new Error(`HTTP ${status}: ${JSON.stringify(data)}`);
    } catch (err) { return fail("run-report", err); }
  }
);

// ─── Helpers ──────────────────────────────────────────────────────────────────
function ok(text: string) {
  return { content: [{ type: "text" as const, text }] };
}
function fail(tool: string, err: unknown) {
  const msg = err instanceof Error ? err.message : String(err);
  console.error(`[cognos-mcp] ${tool} error: ${msg}`);
  return { content: [{ type: "text" as const, text: `Error in ${tool}: ${msg}` }], isError: true as const };
}

// ─── Main ─────────────────────────────────────────────────────────────────────
async function main(): Promise<void> {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error("[cognos-mcp] IBM Cognos Analytics MCP server running on stdio");
}

main().catch((err) => {
  console.error("[cognos-mcp] Fatal:", err);
  process.exit(1);
});

